var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으갸야약……!! 사람 살려……!!","JPN":"ぎゃあああ……！！　助けて……！！","ENG":"Aaaaagh...! Somebody help me...!","TWN":"呀呀呀……！救命啊……！！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"수리야 님! 이렇게까지 깊게 들어온다는 이야기는 없었잖아요!!","JPN":"スーリヤさん！　こんな奥まで入るなんて聞いてませんよ！！","ENG":"Surya! You never said we'd be going this deep into the danger zone!","TWN":"蘇莉耶！不是說好不會下到這麼深的嗎！！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 대체 이 사람 같이 생긴 고철 덩어리는 다 뭔가요! 좀비처럼 계속 따라오는데요!?","JPN":"あと、この人の形をした鉄くずは何ですか？　ゾンビみたいに延々とついてくるんですけど！？","ENG":"And what's with all these scrap heaps that look like people? They're following us like zombies!","TWN":"還有，這個長得像人的廢鐵塊到底是什麼啊！像僵屍一樣一直跟著我！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으아아아!! 가이드고 나발이고, 이러다간 다 죽는다고요……!!","JPN":"わあああ！！　ガイドどころじゃないよもー！　このままだとみんな死んでしまいます……！！","ENG":"Aaah!! Guide or not, we're all gonna die at this rate...!","TWN":"啊啊啊！！什麼指南不指南的，這樣下去我們都會死的……！！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그러니까 말했을 텐데, 아샤. 이건 평범한 투어가 아니라고.","JPN":"だから言っただろう、アーシャ。これは普通のツアーではないと。","ENG":"I told you, Asha. This isn't just some regular tour.","TWN":"所以我說過了，阿莎。這不是普通的旅行。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이번 건은 구 관리국과 관련된 문제니까, 너는 길만 알려주고 빠지라고 하지 않았나?","JPN":"今回の件は旧管理局がらみだから、君は道だけ教えて帰れと言ったはずだ。","ENG":"This one involves the Old Administration, remember? I said you should just give directions and stay out of it.","TWN":"這次的事情與舊管理局有關，不是讓你指路後就離開嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이 정도일 줄은 몰랐다고요! 애초에 로터스에 위험하지 않은 곳이 어디 있다고!","JPN":"こんは大変だなんて知らなかったんです！　そもそもロータスなんてどこへ行っても危ないのは同じですし！","ENG":"I didn't know it'd be this bad! Honestly, is there anywhere in Lotus that isn't dangerous?!","TWN":"沒想到會這樣！一開始就沒有洛德斯的安全之地！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"게다가 수리야 님, 어차피 길치라서 여기 지리를 하나도 모르시잖아요!","JPN":"それにスーリヤさん方向音痴だから、この辺の地理は全くわからないじゃないですか！","ENG":"Besides, Surya, you're terrible with directions! You don't even know the area!","TWN":"而且蘇莉耶，反正你是路癡，對這裡的地理一點都不熟悉吧！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아닐라 님이라면 모를까, 수리야 님 혼자서는 가이드 자체가 성립되지 않는다고요!","JPN":"アニラさんならともかく、スーリヤさん1人だとガイドできないに決まってます！","ENG":"If it were Anila, maybe. But there's no way this tour would work with just you.","TWN":"如果是雅妮拉還好說，但蘇莉耶一個人是無法當這個導遊的！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"크흠, 아직 지도를 다 못 외웠을 뿐이다.","JPN":"ごほん、まだ地図を覚えられていないだけだ。","ENG":"Ahem... I just haven't finished memorizing the map, that's all.","TWN":"咳咳，我只是還沒完全記住地圖而已。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아샤! 정말로 이 길이 맞아?","JPN":"アーシャ！　本当にこの道で合ってる？","ENG":"Asha, are you sure this is the right path?","TWN":"阿莎！這條路真的對嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왠지 아까부터 똑같은 곳을 뺑뺑 돌고 있는 것 같은데?","JPN":"なんか、さっきから同じ場所をぐるぐる回ってる気がするんだけど。","ENG":"It feels like we've been going in circles for a while now...","TWN":"總覺得從剛才開始一直在同一個地方轉圈呢？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"거, 걱정하지 마, 미나야!","JPN":"だ、大丈夫よ、ミナ！","ENG":"D-don't worry, Mina!","TWN":"別，別擔心，米娜！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그래도 이곳 지형은 사전에 충분히 조사해 두었으니까!","JPN":"ここの地形は事前にちゃんと調べてあるから！","ENG":"I did my homework and studied the terrain in advance!","TWN":"不過這裡的地形已經事先充分調查過了！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"무엇보다도…….","JPN":"何より……","ENG":"And more importantly...","TWN":"最重要的是……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"우리 바루나 투어는 클라이언트를 실망시키지 않는 게 모토거든……!","JPN":"うちのヴァルナツアーはクライアントをがっかりさせないのがモットーだから……！","ENG":"At Varuna Tour, we never let a client down. That's our motto.","TWN":"我們伐樓拿旅行社的宗旨就是不讓客戶失望……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 뭐야?","JPN":"急に何？","ENG":"What the?","TWN":"……突然怎麼回事？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"땅 밑에서…? 이건 지진인가……?","JPN":"地面の下から……？　地震……？","ENG":"From underground...? Was that an earthquake...?","TWN":"地下……？這是地震嗎……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"미나야, 거기 가만히 있지 말고 얼른 뛰어……!","JPN":"ミナ、そこに突っ立ってないで早く走って……！","ENG":"Mina, don't just stand there... Run!","TWN":"米娜，別站在那裡，快跑……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"휘말린다고!","JPN":"巻き込まれるわ！","ENG":"You'll get caught in it!","TWN":"被捲進去了！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"휘말려……?","JPN":"巻き込まれる……？","ENG":"Caught in it...?","TWN":"被捲入……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"좋아, 수리야 님! 바로 지금이에요!","JPN":"よし、スーリヤさん！　今です！","ENG":"Now, Surya! This is the moment!","TWN":"好，蘇莉耶！就是現在！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"……알겠다!","JPN":"……承知した！","ENG":"...Got it!","TWN":"……我知道了！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"만트라 코드. 사비트르 활성화!","JPN":"マントラコード。サヴィトリ活性化！","ENG":"Activating mantra code, Savitr.","TWN":"曼陀羅代碼：娑維德利啟動！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야… 이거… 위력이 엄청나잖아……?","JPN":"何……これ……すごい威力……","ENG":"What the... that's insanely powerful...!","TWN":"什麼啊……這……威力也太強了吧……?"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ONLY_VARUNA_CA_CHAKRAM_HYPER_3"},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"순식간에 지면에 커다란 구멍이 생겨 버릴 정도야……!","JPN":"あっという間に地面に大穴ができるほどの……！","ENG":"It left a crater in the ground like it was nothing...!","TWN":"瞬間就會在地面上出現一個大洞……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_06"},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 이건……?","JPN":"いったい、どういう……？","ENG":"What on earth is this...?","TWN":"這到底是……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"휘유! 한 건 해결인가!","JPN":"ふう！　これで一件落着かしら！","ENG":"Whew! That's one issue taken care of!","TWN":"呼喲！解決一個！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그럼, 가이드 해드리겠습니다, 고객님!","JPN":"では、引き続きガイドいたします、お客様！","ENG":"Now then, allow me to guide you!","TWN":"那麼，我來為你帶路吧，客人！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"원래 20년 전에는 이 지역에 사람이 살았다는 건 미나도 알고 있지?","JPN":"20年前はこの地域にも人が住んでたってこと、ミナも知ってるよね？","ENG":"You know, Mina, people actually used to live in this area twenty years ago.","TWN":"原來20年前這裡是有人居住的，米娜也知道吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"기록을 조사해 보니까, 이곳에 지하 시설을 만들려던 흔적이 여러 곳 있더라고.","JPN":"記録を調べたら、ここに地下施設を作ろうとした痕跡がいくつかあったわ。","ENG":"I did some digging through the records and found traces of plans to build underground facilities in this area.","TWN":"調查記錄後發現，這裡有多處建造地下設施的痕跡。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그럼, 당연히 지반이 약해지는 곳이 생길 수밖에 없잖아?","JPN":"そうすると、地盤が弱くなってる場所があってもおかしくないよね？","ENG":"Which means, of course, there are plenty of weak points in the ground.","TWN":"那當然，肯定會有地基變弱的地方吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 그럼 지금까지 같은 곳을 뺑뺑 돌고 있던 이유가…….","JPN":"待って、じゃあ今まで同じ場所をぐるぐる回っていた理由は……","ENG":"Wait... so the reason we kept going in circles until now was...","TWN":"等一下，那我們一直在同一個地方兜圈子的原因是……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"물론, 저 고철 덩어리들을 함정에 빠트리기 위해서 설계한 관광 코스라구!","JPN":"もちろん、あの鉄くずどもを罠に嵌めるために設計した観光コースよ！","ENG":"Obviously! It was a specially designed tour route to lure those scrap heaps into traps!","TWN":"當然，這是為了把那些廢鐵陷入陷阱而設計的觀光路線！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"지반이 약해진 곳을 찾아서, 녀석들을 밀어 넣으려고 말이야.","JPN":"地盤が弱くなっているポイントを見つけてやつらを落とすためにね。","ENG":"We mapped out weakened spots in the terrain and planned to push them in!","TWN":"找到地基鬆軟的地方，把它們推進去。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그렇군, 관광지가 없다면, 만들면 그만이라는 건가……?","JPN":"なるほど、観光スポットがないなら作ればよいということか……？","ENG":"I see... If there's no tourist attraction, just build one yourself, huh?","TWN":"原來如此，如果沒有旅遊景點，那就自己建一個……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그렇다면 지금부터 이곳을 <color=#ffd34c>바루나 협곡</color>이라고 부르도록 하지.","JPN":"では今からここを<color=#ffd34c>ヴァルナ峡谷</color>と呼ぶとしよう。","ENG":"Then from now on, let's call this place... <color=#ffd34c>Varuna Canyon</color>.","TWN":"那麼從現在開始，這裡就叫做<color=#ffd34c>伐樓拿峽谷</color>吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"오, 그 이름 나쁘지 않은데요? 관광 수첩에 추가해 놔야겠다!","JPN":"お、悪くない名前ですね！　観光手帳に追加しておこうっと！","ENG":"Oh, not a bad name! I should jot that down in the tour journal!","TWN":"喔，這個名字不錯啊！得把它加到旅遊手冊裡去！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 너희들…….","JPN":"いや、あなたたち……","ENG":"Seriously...?","TWN":"不是吧，你們……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이건 관광지가 아니라, 그냥 자연 훼손이잖아…….","JPN":"これ、観光スポットじゃなくてただの自然破壊なんじゃ……","ENG":"This isn't a tourist destination... it's just destruction of nature...","TWN":"這不是旅遊景點，只是破壞自然而已……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 약간 이상한 녀석들인 것 같지만…….","JPN":"ま、ちょっと変なところはあるけど……","ENG":"Well, they're definitely a strange bunch...","TWN":"嗯，雖然感覺有點奇怪……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래도 부사장님이 말한 것처럼 실력은 제법인 것 같은데……","JPN":"副社長が言ったとおり、腕は確かなようだね……","ENG":"But I'll admit... they're pretty good, like Vice President said.","TWN":"不過，正如副總所說，實力還是不錯的……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Huh?","TWN":"嗯?"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_05"},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어라? 이거 왜 계속 땅이 흔들리지……?","JPN":"あれ？　なんでまだ地面が揺れてるのかな……？","ENG":"Wait, why is the ground still shaking...?","TWN":"欸？為什麼地面一直在震動……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"미안하다. 아무래도 CRF 출력 조절에 실패한 모양이군.","JPN":"申し訳ない。どうやらCRFの出力調整に失敗したようだ。","ENG":"Sorry. It seems I've failed to properly regulate the CRF output.","TWN":"抱歉，看來我沒能成功調節CRF輸出。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"바루나스트라를 섬멸한 뒤로 만트라 코드를 활성화시킨 적이 없었으니까…….","JPN":"ヴァルナストラを殲滅して以来、マントラコードを活性化したことがなかったから……","ENG":"I haven't activated the mantra code since taking down Varunastra...","TWN":"自從消滅了伐樓拿之艦後，就沒有啟動過曼陀羅代碼……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그, 그런 건 빨리 말해달라고요……!","JPN":"そ、そういうことはもっと早く言ってくださいよ……！","ENG":"T-that's the kind of thing you should mention before it starts shaking...!","TWN":"那，那種事請快點告訴我啊……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"뭘 그렇게 멍하니 있어, 미나야!","JPN":"ぼーっとしてるんじゃないわよ、ミナ！","ENG":"Why are you just standing there, Mina?","TWN":"米娜，你發什麼呆呢！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"얼른 튀자……!","JPN":"早く逃げよう……！","ENG":"Come on... run!","TWN":"快逃……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어, 어어…? 야! 너희들! 같이 가……!","JPN":"え、ええ……？　ちょっと、あなたたち！　待って……！","ENG":"H-hey! Wait! Don't leave me behind...!","TWN":"啊，嗯……？喂！你們！等等我……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};